#include <stdio.h>
#include <stdlib.h>
int main() {
    double k;
    scanf("%lf", &k);
    int n = 1;
    double loaves[1000];
    loaves[0] = 1.0;
    while (1) {
        double max = 0.0;
        int maxIndex = -1;
        for (int i = 0; i < n; i++) {
            if (loaves[i] > max) {
                max = loaves[i];
                maxIndex = i;
            }
        }
        if (max / k < loaves[n-1]) break;
        double cut = max / (k + 1);
        loaves[n] = cut;
        loaves[maxIndex] -= cut;
        n++;
    }
    printf("%d\n", n);
    for (int i = 1; i < n; i++) {
        printf("%d %f\n", i-1, loaves[i]);
    }
    return 0;
}

