code.JavaScript:
const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let k;
rl.on('line', (input) => {
    k = parseFloat(input);
    let n = 1;
    let loaves = [1.0];
    while (true) {
        let max = Math.max(...loaves);
        let maxIndex = loaves.indexOf(max);
        if (max / k < loaves[loaves.length-1]) break;
        let cut = max / (k + 1);
        loaves.push(cut);
        loaves[maxIndex] -= cut;
        n++;
    }
    console.log(n);
    for (let i = 1; i < n; i++) {
        console.log(i-1, loaves[i]);
    }
    rl.close();
});
